/**
 * Split-Screen Viewer for Hotspot Configuration
 * Both views are rotatable - source sets arrow direction, destination sets landing direction
 */
(function() {
    'use strict';

    class SplitScreenViewer {
        constructor() {
            this.sourceScene = null;
            this.destinationScene = null;
            this.sourceRenderer = null;
            this.destinationRenderer = null;
            this.sourceCamera = null;
            this.destinationCamera = null;
            this.sourceControls = null;
            this.destinationControls = null;
            this.sourceSphere = null;
            this.destinationSphere = null;
            this.arrowMarker = null;

            this.isActive = false;
            this.animationId = null;

            // Configuration - match main viewer
            this.sphereRadius = 500;
            this.cameraDistance = 0.1; // Small but not too small
            this.markerDoorRadius = 400; // Same as vr-viewer door radius (sphereRadius * 0.8)
            this.markerDoorHeight = 2.0;
            this.markerRotation = 3.2;

            // Stored data
            this.sourceYaw = 0;
            this.sourcePitch = 0;
            this.destinationYaw = 0;
            this.destinationPitch = 0;

            // Room data
            this.sourceRoomImage = null;
            this.destinationRoomImage = null;
            this.sourceRoomName = '';
            this.destinationRoomName = '';

            // Callbacks
            this.onComplete = null;
            this.onCancel = null;

            // DOM elements
            this.modal = document.getElementById('split-screen-modal');
            this.sourceCanvas = document.getElementById('source-canvas');
            this.destinationCanvas = document.getElementById('destination-canvas');
            this.sourceRoomNameEl = document.getElementById('source-room-name');
            this.destinationRoomNameEl = document.getElementById('destination-room-name');

            this.bindEvents();
        }

        bindEvents() {
            const okBtn = document.getElementById('split-ok-btn');
            const cancelBtn = document.getElementById('split-cancel-btn');

            if (okBtn) {
                okBtn.addEventListener('click', () => this.confirm());
            }

            if (cancelBtn) {
                cancelBtn.addEventListener('click', () => this.cancel());
            }

            // Handle ESC key
            document.addEventListener('keydown', (e) => {
                if (e.key === 'Escape' && this.isActive) {
                    this.cancel();
                }
            });

            // Handle window resize
            window.addEventListener('resize', () => {
                if (this.isActive) {
                    this.handleResize();
                }
            });
        }

        /**
         * Initialize Three.js scenes for both canvases
         */
        init() {
            if (!this.sourceCanvas || !this.destinationCanvas) {
                console.error('Split-screen canvases not found');
                return false;
            }

            // Initialize source scene (arrow direction - rotatable)
            this.initSourceScene();

            // Initialize destination scene (landing direction - rotatable)
            this.initDestinationScene();

            return true;
        }

        initSourceScene() {
            const container = this.sourceCanvas.parentElement;

            // Camera
            this.sourceCamera = new THREE.PerspectiveCamera(
                75,
                container.clientWidth / container.clientHeight,
                0.01,
                1100
            );
            this.sourceCamera.position.set(this.cameraDistance, 0, 0);

            // Scene
            this.sourceScene = new THREE.Scene();

            // Renderer
            this.sourceRenderer = new THREE.WebGLRenderer({
                canvas: this.sourceCanvas,
                antialias: true
            });
            this.sourceRenderer.setPixelRatio(window.devicePixelRatio);
            this.sourceRenderer.setSize(container.clientWidth, container.clientHeight);

            // OrbitControls
            this.sourceControls = new THREE.OrbitControls(this.sourceCamera, this.sourceCanvas);
            this.sourceControls.enableZoom = false;
            this.sourceControls.enablePan = false;
            this.sourceControls.enableRotate = true;
            this.sourceControls.rotateSpeed = -0.25;
            this.sourceControls.target.set(0, 0, 0);
            this.sourceControls.minDistance = this.cameraDistance;
            this.sourceControls.maxDistance = this.cameraDistance;
            // Lock vertical movement to horizon level
            this.sourceControls.minPolarAngle = Math.PI / 2;
            this.sourceControls.maxPolarAngle = Math.PI / 2;

            // Create arrow marker for source view
            this.createArrowMarker();
        }

        initDestinationScene() {
            const container = this.destinationCanvas.parentElement;

            // Camera
            this.destinationCamera = new THREE.PerspectiveCamera(
                75,
                container.clientWidth / container.clientHeight,
                0.01,
                1100
            );
            this.destinationCamera.position.set(this.cameraDistance, 0, 0);

            // Scene
            this.destinationScene = new THREE.Scene();

            // Renderer
            this.destinationRenderer = new THREE.WebGLRenderer({
                canvas: this.destinationCanvas,
                antialias: true
            });
            this.destinationRenderer.setPixelRatio(window.devicePixelRatio);
            this.destinationRenderer.setSize(container.clientWidth, container.clientHeight);

            // OrbitControls
            this.destinationControls = new THREE.OrbitControls(this.destinationCamera, this.destinationCanvas);
            this.destinationControls.enableZoom = false;
            this.destinationControls.enablePan = false;
            this.destinationControls.enableRotate = true;
            this.destinationControls.rotateSpeed = -0.25;
            this.destinationControls.target.set(0, 0, 0);
            this.destinationControls.minDistance = this.cameraDistance;
            this.destinationControls.maxDistance = this.cameraDistance;
            // Lock vertical movement to horizon level
            this.destinationControls.minPolarAngle = Math.PI / 2;
            this.destinationControls.maxPolarAngle = Math.PI / 2;
        }

        /**
         * Create 3D ring marker for source view
         */
        createArrowMarker() {
            const ringGeometry = new THREE.RingGeometry(39, 60, 64);
            const ringMaterial = new THREE.MeshBasicMaterial({
                color: 0x0073e6, // --primary: hsl(210 100% 45%)
                transparent: false,
                depthTest: false,
                depthWrite: false,
                side: THREE.DoubleSide
            });
            this.arrowMarker = new THREE.Mesh(ringGeometry, ringMaterial);
            this.arrowMarker.renderOrder = 998;
            this.sourceScene.add(this.arrowMarker);
        }

        /**
         * Update arrow marker position to always be in front of camera
         */
        updateArrowMarker() {
            if (!this.sourceCamera || !this.sourceControls || !this.arrowMarker) return;

            // Match vr-viewer placement/orientation logic exactly.
            const theta = -this.sourceControls.getAzimuthalAngle() - Math.PI / 2;
            const doorPosition = {
                x: this.markerDoorRadius * Math.sin(this.markerDoorHeight) * Math.cos(theta),
                y: this.markerDoorRadius * Math.cos(this.markerDoorHeight),
                z: this.markerDoorRadius * Math.sin(this.markerDoorHeight) * Math.sin(theta)
            };

            this.arrowMarker.position.x = doorPosition.x;
            this.arrowMarker.position.y = doorPosition.y;
            this.arrowMarker.position.z = doorPosition.z;

            this.arrowMarker.rotation.order = 'YXZ';
            this.arrowMarker.rotation.x = Math.PI / 2 + this.markerRotation;
            this.arrowMarker.rotation.y = -theta + Math.PI / 2;
            this.arrowMarker.rotation.z = Math.PI;
        }

        /**
         * Create panorama sphere with texture
         */
        createSphere(scene, imageUrl, callback) {
            const textureLoader = new THREE.TextureLoader();

            textureLoader.load(imageUrl, (texture) => {
                // Create sphere geometry (inverted for inside viewing)
                const geometry = new THREE.SphereGeometry(this.sphereRadius, 60, 40);
                geometry.scale(-1, 1, 1); // Invert for inside viewing

                const material = new THREE.MeshBasicMaterial({
                    map: texture
                });

                const sphere = new THREE.Mesh(geometry, material);
                scene.add(sphere);

                if (callback) callback(sphere);
            }, undefined, (error) => {
                console.error('Error loading panorama texture:', error);
            });
        }

        /**
         * Set camera direction based on yaw/pitch
         * Uses same calculation as main VR viewer's cameraMove/fadeProd
         */
        setCameraDirection(camera, controls, yaw, pitch) {
            // Convert yaw/pitch back to spherical coordinates
            const phi = THREE.MathUtils.degToRad(pitch);
            const theta = -THREE.MathUtils.degToRad(yaw) - Math.PI / 2;

