(function() {
    'use strict';

    // ============================================================================
    // Helpers: htmx.ajax with HTTP error handling
    // ============================================================================

    // For swap: 'none' - rejects on HTTP errors
    function htmxAjaxWithError(method, url, options = {}) {
        return new Promise((resolve, reject) => {
            htmx.ajax(method, url, {
                ...options,
                handler: (_elt, info) => {
                    const status = info.xhr?.status || 0;
                    status >= 400 ? reject(new Error(`HTTP ${status}`)) : resolve();
                }
            });
        });
    }

    // For swap cases - rejects on HTTP errors, lets htmx do the swap
    function htmxAjaxSwap(method, url, options = {}) {
        return new Promise((resolve, reject) => {
            options.source.addEventListener('htmx:afterRequest', (evt) => {
                const status = evt.detail.xhr?.status || 0;
                status >= 400 ? reject(new Error(`HTTP ${status}`)) : resolve();
            }, { once: true });

            htmx.ajax(method, url, options);
        });
    }

    // ============================================================================
    // VrStorage - Data management (original: VrStorage.js)
    // ============================================================================
    class VrStorage {
        constructor() {
            this.scaler = 10;
            this.animScale = 0.02;
            this.debug = false;

            this.sphereRadius = 50 * this.scaler; // 500
            this.doorRadius = this.sphereRadius * 0.8; // 400
            this.arrowScaler = (2 * this.scaler) / 10; // 2
            this.interferenceScaler = 1.01;

            this.arrowUrl = '/images/arrow.png';
            this.arrowLoadingUrl = '/images/arrow_loading.png';

            // Room data storage
            this.sphereData = {};
            this.sphereMeshes = {};
            this.doorMeshes = {};
            this.doors = {};

            // Load rooms data from server
            this.roomsArray = [];
            const roomsDataElement = document.getElementById('rooms-data');
            if (roomsDataElement) {
                this.roomsArray = JSON.parse(roomsDataElement.textContent);
                this.buildSphereData();
                this.buildDoorsFromHotspots();
            }
        }

        /**
         * Build sphereData object from roomsArray
         * Original uses object with ID keys, we convert array to same format
         */
        buildSphereData() {
            this.sphereData = {};
            this.roomsArray.forEach((room) => {
                this.sphereData[room.id] = {
                    id: room.id,
                    name: room.name,
                    img_url: room.image,
                    angle: room.angle || 0,  // Sphere rotation (radians)
                    default_yaw: room.default_yaw || 0,
                    default_pitch: room.default_pitch || 0,
                    is_entrance: room.is_entrance || false,
                    hotspots_data: room.hotspots_data || [],
                };
            });
        }

        /**
         * Build doors map from hotspots_data
         * Original: graph[fromRoomId][toRoomId] = { phi, theta }
         * We convert yaw/pitch (degrees) to theta/phi (radians)
         */
        buildDoorsFromHotspots() {
            this.doors = {};

            for (let roomId in this.sphereData) {
                const room = this.sphereData[roomId];
                if (!room.hotspots_data || room.hotspots_data.length === 0) continue;

                this.doors[roomId] = {};

                room.hotspots_data.forEach((hotspot) => {
                    // Convert yaw from degrees to radians for theta
                    const theta = THREE.MathUtils.degToRad(hotspot.yaw);
                    // Convert pitch to phi (original uses π/2 for equator)
                    const phi = THREE.MathUtils.degToRad(90 - (hotspot.pitch || 0));
                    // Use target_room as key (matches original structure)
                    this.doors[roomId][hotspot.target_room] = {
                        phi: phi,
                        theta: theta
                    };
                });
            }
        }

        /**
         * Reload rooms data from page
         */
        reloadRoomsData() {
            const roomsDataElement = document.getElementById('rooms-data');
            if (roomsDataElement) {
                this.roomsArray = JSON.parse(roomsDataElement.textContent);
                this.buildSphereData();
                this.buildDoorsFromHotspots();
            }
        }

        hasDownloadUrl(roomId) {
            return this.roomExists(roomId) && this.sphereData[roomId].img_url;
        }

        roomExists(roomId) {
            return !!this.sphereData[roomId];
        }

        getFirstRoomId() {
            return this.roomsArray.length > 0 ? this.roomsArray[0].id : null;
        }

        getRoomIndex(roomId) {
            return this.roomsArray.findIndex(r => r.id === roomId);
        }
    }

