package utils

import "math"

// CalculateDestinationAngle calculates the sphere rotation angle for the destination room.
// This ensures the user sees the landing direction content when arriving from the arrow direction.
//
// arrowYaw: the yaw angle (degrees) where the arrow is placed in the source room
// landingYaw: the yaw angle (degrees) the user should see when landing in the destination room
//
// Returns the sphere rotation in radians.
func CalculateDestinationAngle(arrowYaw, landingYaw float64) float64 {
	return DegToRad(landingYaw - arrowYaw)
}

// CalculateBackArrowYaw calculates the yaw position for the back-reference arrow.
// The back arrow should appear 180° behind the user in world coordinates.
//
// arrowYaw: the yaw angle (degrees) of the forward arrow in the source room
//
// Returns the back arrow yaw in degrees, normalized to 0-360 range.
func CalculateBackArrowYaw(arrowYaw float64) float64 {
	backYaw := arrowYaw + 180
	return NormalizeAngle(backYaw)
}

// NormalizeAngle normalizes an angle to the 0-360 degree range.
func NormalizeAngle(angle float64) float64 {
	for angle < 0 {
		angle += 360
	}
	for angle >= 360 {
		angle -= 360
	}
	return angle
}

// DegToRad converts degrees to radians.
func DegToRad(deg float64) float64 {
	return deg * math.Pi / 180
}

// RadToDeg converts radians to degrees.
func RadToDeg(rad float64) float64 {
	return rad * 180 / math.Pi
}

package utils

import (
	"math"
	"testing"
)

func TestCalculateDestinationAngle(t *testing.T) {
	tests := []struct {
		name        string
		arrowYaw    float64
		landingYaw  float64
		expectedDeg float64 // expected result in degrees for readability
	}{
		{
			name:        "going straight - arrow and landing same direction",
			arrowYaw:    0,
			landingYaw:  0,
			expectedDeg: 0,
		},
		{
			name:        "looking back - landing 180° from arrow",
			arrowYaw:    0,
			landingYaw:  180,
			expectedDeg: 180,
		},
		{
			name:        "turn right 90° - arrow forward, land looking right",
			arrowYaw:    0,
			landingYaw:  90,
			expectedDeg: 90,
		},
		{
			name:        "turn left 90° - arrow forward, land looking left",
			arrowYaw:    0,
			landingYaw:  -90,
			expectedDeg: -90,
		},
		{
			name:        "arrow at 90°, landing at 0°",
			arrowYaw:    90,
			landingYaw:  0,
			expectedDeg: -90,
		},
		{
			name:        "arrow at 45°, landing at 225° (looking back)",
			arrowYaw:    45,
			landingYaw:  225,
			expectedDeg: 180,
		},
		{
			name:        "arrow at 270°, landing at 270° (going straight)",
			arrowYaw:    270,
			landingYaw:  270,
			expectedDeg: 0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := CalculateDestinationAngle(tt.arrowYaw, tt.landingYaw)
			expectedRad := DegToRad(tt.expectedDeg)

			// Allow small floating point tolerance
			if math.Abs(result-expectedRad) > 0.0001 {
				t.Errorf("CalculateDestinationAngle(%v, %v) = %v rad (%v°), want %v rad (%v°)",
					tt.arrowYaw, tt.landingYaw,
					result, RadToDeg(result),
					expectedRad, tt.expectedDeg)
			}
		})
	}
}

func TestCalculateBackArrowYaw(t *testing.T) {
	tests := []struct {
		name     string
		arrowYaw float64
		expected float64
	}{
		{
			name:     "arrow at 0° - back arrow at 180°",
			arrowYaw: 0,
			expected: 180,
		},
		{
			name:     "arrow at 90° - back arrow at 270°",
			arrowYaw: 90,
			expected: 270,
		},
		{
			name:     "arrow at 180° - back arrow at 360° (normalized to 0°)",
			arrowYaw: 180,
			expected: 0,
		},
		{
			name:     "arrow at 270° - back arrow at 90°",
			arrowYaw: 270,
			expected: 90,
		},
		{
			name:     "arrow at -90° (270°) - back arrow at 90°",
			arrowYaw: -90,
			expected: 90,
		},
		{
			name:     "arrow at 45° - back arrow at 225°",
			arrowYaw: 45,
			expected: 225,
		},
		{
			name:     "arrow at 350° - back arrow at 170°",
			arrowYaw: 350,
			expected: 170,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := CalculateBackArrowYaw(tt.arrowYaw)

			if math.Abs(result-tt.expected) > 0.0001 {
				t.Errorf("CalculateBackArrowYaw(%v) = %v, want %v",
					tt.arrowYaw, result, tt.expected)
			}
		})
	}
}

func TestNormalizeAngle(t *testing.T) {
	tests := []struct {
		name     string
		angle    float64
		expected float64
	}{
		{"0° stays 0°", 0, 0},
		{"90° stays 90°", 90, 90},
		{"360° becomes 0°", 360, 0},
		{"450° becomes 90°", 450, 90},
		{"-90° becomes 270°", -90, 270},
		{"-180° becomes 180°", -180, 180},
		{"-360° becomes 0°", -360, 0},
		{"720° becomes 0°", 720, 0},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := NormalizeAngle(tt.angle)

			if math.Abs(result-tt.expected) > 0.0001 {
				t.Errorf("NormalizeAngle(%v) = %v, want %v",
					tt.angle, result, tt.expected)
			}
		})
	}
}

