            this.destinationYaw = initialDestinationYaw ?? (this.sourceYaw + 180);
            this.destinationPitch = initialDestinationPitch ?? 90;  // Default to horizon (phi=90°)
            this.onComplete = onComplete;
            this.onCancel = onCancel;

            // Update UI labels
            if (this.sourceRoomNameEl) {
                this.sourceRoomNameEl.textContent = sourceRoomName;
            }
            if (this.destinationRoomNameEl) {
                this.destinationRoomNameEl.textContent = destinationRoomName;
            }

            // Show modal
            this.modal.classList.remove('hidden');
            this.isActive = true;

            // Initialize scenes if not already done
            if (!this.sourceScene) {
                this.init();
            }

            // Handle resize after modal is visible
            setTimeout(() => {
                this.handleResize();

                // Clear any existing spheres
                this.clearScenes();

                // Load panoramas
                this.createSphere(this.sourceScene, sourceRoomImage, (sphere) => {
                    this.sourceSphere = sphere;
                    this.setCameraDirection(this.sourceCamera, this.sourceControls, this.sourceYaw, this.sourcePitch);
                });

                this.createSphere(this.destinationScene, destinationRoomImage, (sphere) => {
                    this.destinationSphere = sphere;
                    this.setCameraDirection(this.destinationCamera, this.destinationControls, this.destinationYaw, this.destinationPitch);
                });

                // Start animation loop
                this.animate();
            }, 100);
        }

        /**
         * Clear scenes (remove spheres but keep arrow marker)
         */
        clearScenes() {
            if (this.sourceSphere) {
                this.sourceScene.remove(this.sourceSphere);
                this.sourceSphere.geometry.dispose();
                this.sourceSphere.material.map?.dispose();
                this.sourceSphere.material.dispose();
                this.sourceSphere = null;
            }

            if (this.destinationSphere) {
                this.destinationScene.remove(this.destinationSphere);
                this.destinationSphere.geometry.dispose();
                this.destinationSphere.material.map?.dispose();
                this.destinationSphere.material.dispose();
                this.destinationSphere = null;
            }
        }

        /**
         * Handle window resize
         */
        handleResize() {
            if (!this.isActive) return;

            // Source canvas
            const sourceContainer = this.sourceCanvas.parentElement;
            if (this.sourceCamera && this.sourceRenderer) {
                this.sourceCamera.aspect = sourceContainer.clientWidth / sourceContainer.clientHeight;
                this.sourceCamera.updateProjectionMatrix();
                this.sourceRenderer.setSize(sourceContainer.clientWidth, sourceContainer.clientHeight);
            }

            // Destination canvas
            const destContainer = this.destinationCanvas.parentElement;
            if (this.destinationCamera && this.destinationRenderer) {
                this.destinationCamera.aspect = destContainer.clientWidth / destContainer.clientHeight;
                this.destinationCamera.updateProjectionMatrix();
                this.destinationRenderer.setSize(destContainer.clientWidth, destContainer.clientHeight);
            }
        }

        /**
         * Animation loop
         */
        animate() {
            if (!this.isActive) return;

            this.animationId = requestAnimationFrame(() => this.animate());

            // Update controls
            if (this.sourceControls) this.sourceControls.update();
            if (this.destinationControls) this.destinationControls.update();

            // Update arrow marker to follow camera direction
            this.updateArrowMarker();

            // Render
            if (this.sourceRenderer && this.sourceScene && this.sourceCamera) {
                this.sourceRenderer.render(this.sourceScene, this.sourceCamera);
            }
            if (this.destinationRenderer && this.destinationScene && this.destinationCamera) {
                this.destinationRenderer.render(this.destinationScene, this.destinationCamera);
            }
        }

        /**
         * Stop animation loop
         */
        stopAnimation() {
            if (this.animationId) {
                cancelAnimationFrame(this.animationId);
                this.animationId = null;
            }
        }

        /**
         * Close the modal
         */
        close() {
            this.isActive = false;
            this.stopAnimation();
            this.modal.classList.add('hidden');
        }

        /**
         * Confirm and save - returns both source (arrow) and destination (landing) directions
         */
        confirm() {
            // Get current directions from both cameras using OrbitControls
            const sourceDirection = this.getCameraDirection(this.sourceControls);
            const destDirection = this.getCameraDirection(this.destinationControls);

            console.log('SplitScreen confirm - sourceDirection:', sourceDirection);
            console.log('SplitScreen confirm - destDirection:', destDirection);

            // Calculate destination room angle (sphere rotation) from landing direction
            // The camera arrives looking in the arrow direction (world space)
            // We want user to see content at landingYaw, so rotate sphere by the difference
            let destinationAngle = THREE.MathUtils.degToRad(destDirection.yaw - sourceDirection.yaw);
            console.log('destinationAngle:', destinationAngle, 'radians =', THREE.MathUtils.radToDeg(destinationAngle), 'degrees');

            this.close();

            if (this.onComplete) {
                // Pass both arrow direction (source) and landing direction (destination)
                const result = {
                    arrowYaw: sourceDirection.yaw,
                    arrowPitch: sourceDirection.pitch,
                    landingYaw: destDirection.yaw,
                    landingPitch: destDirection.pitch,
                    destinationAngle: destinationAngle  // Sphere rotation for destination room
                };
                console.log('SplitScreen confirm - sending result:', result);
                this.onComplete(result);
            }
        }

        /**
         * Cancel without saving
         */
        cancel() {
            this.close();

            if (this.onCancel) {
                this.onCancel();
            }
        }

        /**
         * Get the current source (arrow) direction
         */
        getSourceDirection() {
            if (!this.sourceControls) return null;
            return this.getCameraDirection(this.sourceControls);
        }

        /**
         * Get the current destination (landing) direction
         */
        getDestinationDirection() {
            if (!this.destinationControls) return null;
            return this.getCameraDirection(this.destinationControls);
        }
    }

    // Export to global scope
    window.SplitScreenViewer = SplitScreenViewer;
})();

