views/pages/flat_templ.go:78:			templ_7745c5c3_Err = templruntime.WriteString(templ_7745c5c3_Buffer, 4, " <!-- Three.js library --> <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script> <!-- 360° Viewer initialization --> <script>
			(function() {
				const container = document.getElementById('viewer-container');
				const loading = document.getElementById('loading');
				const roomNameEl = document.getElementById('room-name');

				if (!container) {
					console.error('Viewer container not found');
					return;
				}

				// All rooms data from server
				const roomsData = JSON.parse(document.getElementById('rooms-data').textContent);
				let currentRoomIndex = JSON.parse(document.getElementById('current-room-index').textContent);

				// Three.js scene setup
				let camera, scene, renderer, sphere, raycaster, mouse;
				let hotspotMeshes = []; // Array to store hotspot 3D objects
				let isUserInteracting = false;
				let onPointerDownMouseX = 0, onPointerDownMouseY = 0;
				let lon = 0, lat = 0;
				let onPointerDownLon = 0, onPointerDownLat = 0;
				let phi = 0, theta = 0;
				let isTransitioning = false;
				const baseFOV = 75;
				const zoomFOV = 45; // Lower FOV = zoom IN (narrower view)

				function init() {
					// Create camera
					camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 1, 1100);
					camera.target = new THREE.Vector3(0, 0, 0);

					// Create scene
					scene = new THREE.Scene();

					// Raycaster for hotspot click detection
					raycaster = new THREE.Raycaster();
					mouse = new THREE.Vector2();

					// Create sphere geometry (inverted for panorama)
					const geometry = new THREE.SphereGeometry(500, 60, 40);
					geometry.scale(-1, 1, 1); // Invert the sphere

					// Create renderer
					renderer = new THREE.WebGLRenderer();
					renderer.setPixelRatio(window.devicePixelRatio);
					renderer.setSize(window.innerWidth, window.innerHeight);
					container.appendChild(renderer.domElement);

					// Event listeners
					container.addEventListener('pointerdown', onPointerDown);
					container.addEventListener('pointermove', onPointerMove);
					container.addEventListener('pointerup', onPointerUp);
					container.addEventListener('click', onHotspotClick);
					window.addEventListener('resize', onWindowResize);

					// Load initial room
					loadRoom(currentRoomIndex);
				}

				function loadRoom(roomIndex, withTransition = false, hotspotYaw = null, hotspotPitch = null) {
					if (isTransitioning) return;

					const room = roomsData[roomIndex];
					currentRoomIndex = roomIndex;

					if (withTransition && hotspotYaw !== null && hotspotPitch !== null) {
						// Turn camera to face hotspot, then zoom in and load room
						isTransitioning = true;

						// First, smoothly rotate camera to face the hotspot
						animateCameraRotation(lon, lat, hotspotYaw, hotspotPitch, 400, function() {
							// Then zoom in
							animateZoom(baseFOV, zoomFOV, 400, function() {
								// Instantly reset FOV to normal
								camera.fov = baseFOV;
								camera.updateProjectionMatrix();

								// Load new room at normal zoom
								loadRoomContent(room, function() {
									isTransitioning = false;
								});
							});
						});
					} else {
						// No transition for initial load
						loadRoomContent(room, null);
					}
				}

				function loadRoomContent(room, callback) {
					// Update room name in UI
					if (roomNameEl) {
						roomNameEl.textContent = room.Name;
					}

					// Set default viewing angle
					lon = room.DefaultYaw;
					lat = room.DefaultPitch;

					// Clear existing hotspots
					hotspotMeshes.forEach(mesh => scene.remove(mesh));
					hotspotMeshes = [];

					// Remove old sphere if exists
					if (sphere) {
						scene.remove(sphere);
					}

					// Load texture
					const textureLoader = new THREE.TextureLoader();
					console.log('Loading texture from:', room.ImageURL);

					textureLoader.load(
						room.ImageURL,
						function(texture) {
							console.log('Texture loaded successfully');

							// Create new sphere with texture
							const geometry = new THREE.SphereGeometry(500, 60, 40);
							geometry.scale(-1, 1, 1);
							const material = new THREE.MeshBasicMaterial({ map: texture });
							sphere = new THREE.Mesh(geometry, material);
							scene.add(sphere);

							// Add hotspots for this room
							createHotspots(room.Hotspots);

							// Hide loading indicator
							loading.style.display = 'none';

							// Start animation if not already running
							if (!renderer.info.render.frame) {
								animate();
							}

							// Execute callback if provided
							if (callback) callback();
						},
						function(progress) {
							console.log('Loading progress:', (progress.loaded / progress.total * 100).toFixed(2) + '%');
						},
						function(error) {
							console.error('Error loading texture:', error);
							loading.innerHTML = '<div class="text-red-500">Error loading 360° image. Check console for details.</div>';
							if (callback) callback();
						}
					);
				}

				function animateCameraRotation(startYaw, startPitch, endYaw, endPitch, duration, callback) {
					const startTime = Date.now();

					// Normalize angle difference to take shortest path (-180 to +180)
					let yawDiff = endYaw - startYaw;
					while (yawDiff > 180) yawDiff -= 360;
					while (yawDiff < -180) yawDiff += 360;

					const pitchDiff = endPitch - startPitch;

					function step() {
						const elapsed = Date.now() - startTime;
						const progress = Math.min(elapsed / duration, 1);

						// Easing function (easeInOutCubic)
						const eased = progress < 0.5
							? 4 * progress * progress * progress
							: 1 - Math.pow(-2 * progress + 2, 3) / 2;

						lon = startYaw + yawDiff * eased;
						lat = startPitch + pitchDiff * eased;

						if (progress < 1) {
							requestAnimationFrame(step);
						} else {
							if (callback) callback();
						}
					}

					step();
				}

				function animateZoom(startFOV, endFOV, duration, callback) {
					const startTime = Date.now();

					function step() {
						const elapsed = Date.now() - startTime;
						const progress = Math.min(elapsed / duration, 1);

						// Easing function (easeInOutCubic)
						const eased = progress < 0.5
							? 4 * progress * progress * progress
							: 1 - Math.pow(-2 * progress + 2, 3) / 2;

						camera.fov = startFOV + (endFOV - startFOV) * eased;
						camera.updateProjectionMatrix();

						if (progress < 1) {
							requestAnimationFrame(step);
						} else {
							if (callback) callback();
						}
					}

					step();
				}

				function createHotspots(hotspots) {
					console.log('Creating hotspots:', hotspots);

					if (!hotspots || hotspots.length === 0) {
						console.log('No hotspots to create');
						return;
					}

					hotspots.forEach((hotspot, index) => {
						console.log(`Creating hotspot ${index}:`, hotspot);

						// Create hotspot as a sphere (arrow/icon would be better in production)
						const hotspotGeometry = new THREE.SphereGeometry(15, 16, 16);
						const hotspotMaterial = new THREE.MeshBasicMaterial({
							color: 0xFF6B6B, // Coral color from branding
							transparent: true,
							opacity: 0.8
						});
						const hotspotMesh = new THREE.Mesh(hotspotGeometry, hotspotMaterial);

						// Position hotspot using spherical coordinates
						const radius = 480; // Just inside the panorama sphere
						const phi = THREE.MathUtils.degToRad(90 - hotspot.Pitch);
						const theta = THREE.MathUtils.degToRad(hotspot.Yaw);

						hotspotMesh.position.x = radius * Math.sin(phi) * Math.cos(theta);
						hotspotMesh.position.y = radius * Math.cos(phi);
						hotspotMesh.position.z = radius * Math.sin(phi) * Math.sin(theta);

						console.log(`Hotspot ${index} position:`, hotspotMesh.position);

						// Store target room index and hotspot direction in userData
						hotspotMesh.userData.targetRoom = hotspot.TargetRoom;
						hotspotMesh.userData.label = hotspot.Label;
						hotspotMesh.userData.yaw = hotspot.Yaw;
						hotspotMesh.userData.pitch = hotspot.Pitch;

						scene.add(hotspotMesh);
						hotspotMeshes.push(hotspotMesh);
					});

					console.log('Total hotspots created:', hotspotMeshes.length);
				}

				function onWindowResize() {
					camera.aspect = window.innerWidth / window.innerHeight;
					camera.updateProjectionMatrix();
					renderer.setSize(window.innerWidth, window.innerHeight);
				}

				function onPointerDown(event) {
					isUserInteracting = true;
					onPointerDownMouseX = event.clientX;
					onPointerDownMouseY = event.clientY;
					onPointerDownLon = lon;
					onPointerDownLat = lat;
				}

				function onPointerMove(event) {
					if (isUserInteracting) {
						lon = (onPointerDownMouseX - event.clientX) * 0.1 + onPointerDownLon;
						lat = (event.clientY - onPointerDownMouseY) * 0.1 + onPointerDownLat;
					} else {
						// Update mouse position for hover effects
						mouse.x = (event.clientX / window.innerWidth) * 2 - 1;
						mouse.y = -(event.clientY / window.innerHeight) * 2 + 1;

						// Check if hovering over hotspot
						raycaster.setFromCamera(mouse, camera);
						const intersects = raycaster.intersectObjects(hotspotMeshes);

						// Reset all hotspot scales
						hotspotMeshes.forEach(mesh => {
							mesh.scale.set(1, 1, 1);
							mesh.material.opacity = 0.8;
						});

						// Highlight hovered hotspot
						if (intersects.length > 0) {
