/**
 * Unit tests for hotspot math calculations
 * Run with: node public/js/hotspot-math.test.js
 *
 * These tests verify the same logic used in split-screen-viewer.js
 */

// Helper functions (same as in Go utils)
function degToRad(deg) {
    return deg * Math.PI / 180;
}

function radToDeg(rad) {
    return rad * 180 / Math.PI;
}

function normalizeAngle(angle) {
    while (angle < 0) angle += 360;
    while (angle >= 360) angle -= 360;
    return angle;
}

/**
 * Calculate destination angle (sphere rotation) for landing direction.
 * This is the formula used in split-screen-viewer.js confirm() method.
 *
 * @param {number} arrowYaw - Arrow direction in degrees
 * @param {number} landingYaw - Landing direction in degrees
 * @returns {number} Sphere rotation in radians
 */
function calculateDestinationAngle(arrowYaw, landingYaw) {
    return degToRad(landingYaw - arrowYaw);
}

/**
 * Calculate back arrow position in world coordinates.
 *
 * @param {number} arrowYaw - Forward arrow direction in degrees
 * @returns {number} Back arrow yaw in degrees (normalized 0-360)
 */
function calculateBackArrowYaw(arrowYaw) {
    return normalizeAngle(arrowYaw + 180);
}

// Simple test runner
let passed = 0;
let failed = 0;

function test(name, fn) {
    try {
        fn();
        console.log(`  ✓ ${name}`);
        passed++;
    } catch (e) {
        console.log(`  ✗ ${name}`);
        console.log(`    Error: ${e.message}`);
        failed++;
    }
}

function assertEqual(actual, expected, tolerance = 0.0001) {
    if (Math.abs(actual - expected) > tolerance) {
        throw new Error(`Expected ${expected}, got ${actual}`);
    }
}

// Tests
console.log('\n--- calculateDestinationAngle tests ---\n');

test('going straight - arrow and landing same direction', () => {
    const result = calculateDestinationAngle(0, 0);
    assertEqual(result, 0);
});

test('looking back - landing 180° from arrow', () => {
    const result = calculateDestinationAngle(0, 180);
    assertEqual(result, degToRad(180));
});

test('turn right 90°', () => {
    const result = calculateDestinationAngle(0, 90);
    assertEqual(result, degToRad(90));
});

test('turn left 90°', () => {
    const result = calculateDestinationAngle(0, -90);
    assertEqual(result, degToRad(-90));
});

test('arrow at 90°, landing at 0°', () => {
    const result = calculateDestinationAngle(90, 0);
    assertEqual(result, degToRad(-90));
});

test('arrow at 45°, landing at 225° (looking back)', () => {
    const result = calculateDestinationAngle(45, 225);
    assertEqual(result, degToRad(180));
});

test('arrow at 270°, landing at 270° (going straight)', () => {
    const result = calculateDestinationAngle(270, 270);
    assertEqual(result, 0);
});

console.log('\n--- calculateBackArrowYaw tests ---\n');

test('arrow at 0° - back arrow at 180°', () => {
    assertEqual(calculateBackArrowYaw(0), 180);
});

test('arrow at 90° - back arrow at 270°', () => {
    assertEqual(calculateBackArrowYaw(90), 270);
});

test('arrow at 180° - back arrow at 0° (normalized)', () => {
    assertEqual(calculateBackArrowYaw(180), 0);
});

test('arrow at 270° - back arrow at 90°', () => {
    assertEqual(calculateBackArrowYaw(270), 90);
});

test('arrow at -90° - back arrow at 90°', () => {
    assertEqual(calculateBackArrowYaw(-90), 90);
});

test('arrow at 45° - back arrow at 225°', () => {
    assertEqual(calculateBackArrowYaw(45), 225);
});

test('arrow at 350° - back arrow at 170°', () => {
    assertEqual(calculateBackArrowYaw(350), 170);
});

console.log('\n--- normalizeAngle tests ---\n');

test('0° stays 0°', () => assertEqual(normalizeAngle(0), 0));
test('90° stays 90°', () => assertEqual(normalizeAngle(90), 90));
test('360° becomes 0°', () => assertEqual(normalizeAngle(360), 0));
test('450° becomes 90°', () => assertEqual(normalizeAngle(450), 90));
test('-90° becomes 270°', () => assertEqual(normalizeAngle(-90), 270));
test('-180° becomes 180°', () => assertEqual(normalizeAngle(-180), 180));
test('-360° becomes 0°', () => assertEqual(normalizeAngle(-360), 0));

console.log('\n--- Real-world scenarios ---\n');

test('Walk forward through doorway, keep looking forward', () => {
    const arrowYaw = 0;
    const landingYaw = 0;

    const destAngle = calculateDestinationAngle(arrowYaw, landingYaw);
    const backArrowYaw = calculateBackArrowYaw(arrowYaw);

    assertEqual(destAngle, 0, 0.0001);
    assertEqual(backArrowYaw, 180);
});

test('Walk through doorway on right, turn to face back', () => {
    const arrowYaw = 90;
    const landingYaw = 270;

    const destAngle = calculateDestinationAngle(arrowYaw, landingYaw);
    const backArrowYaw = calculateBackArrowYaw(arrowYaw);

    assertEqual(destAngle, degToRad(180));
    assertEqual(backArrowYaw, 270);
});

test('Walk left, land looking right', () => {
    const arrowYaw = 270;
    const landingYaw = 90;

    const destAngle = calculateDestinationAngle(arrowYaw, landingYaw);
    const backArrowYaw = calculateBackArrowYaw(arrowYaw);

    assertEqual(destAngle, degToRad(-180));
    assertEqual(backArrowYaw, 90);
});

// Summary
console.log('\n========================================');
console.log(`Tests: ${passed} passed, ${failed} failed`);
console.log('========================================\n');

if (failed > 0) {
    process.exit(1);
}

