func HotspotDelete(e *core.RequestEvent) error {
	hotspotId := e.Request.PathValue("id")

	if hotspotId == "" {
		e.App.Logger().Error("Hotspot ID is required", "error", "missing hotspotId")
		lib.ShowToast(e, lib.Toast{Type: lib.ToastError, Key: "hotspot_id_required"})
		e.Response.WriteHeader(http.StatusBadRequest)
		return nil
	}

	// Find the hotspot record
	hotspotRecord, err := e.App.FindRecordById("hotspots", hotspotId)
	if err != nil {
		e.App.Logger().Error("Hotspot not found", "error", err.Error(), "hotspotId", hotspotId)
		lib.ShowToast(e, lib.Toast{Type: lib.ToastError, Key: "hotspot_not_found"})
		e.Response.WriteHeader(http.StatusNotFound)
		return nil
	}

	// Get paired hotspot ID before deletion
	pairedHotspotId := hotspotRecord.GetString("paired_hotspot")

	// Find all rooms that reference this hotspot
	var roomRecords []*core.Record
	err = e.App.RecordQuery("rooms").
		AndWhere(dbx.Like("hotspots", hotspotId)).
		All(&roomRecords)

	if err != nil {
		e.App.Logger().Error("Failed to query rooms", "error", err.Error(), "hotspotId", hotspotId)
		lib.ShowToast(e, lib.Toast{Type: lib.ToastError, Key: "rooms_fetch_error"})
		e.Response.WriteHeader(http.StatusInternalServerError)
		return nil
	}

	// Remove hotspot reference from all rooms
	for _, room := range roomRecords {
		hotspotok := room.GetStringSlice("hotspots")
		var updatedHotspotok []string

		// Filter out the hotspot being deleted
		for _, id := range hotspotok {
			if id != hotspotId {
				updatedHotspotok = append(updatedHotspotok, id)
			}
		}

		room.Set("hotspots", updatedHotspotok)

		if err := e.App.Save(room); err != nil {
			e.App.Logger().Error("Failed to update room hotspots", "error", err.Error(), "roomId", room.Id)
			// Continue trying to delete from other rooms
		}
	}

	// Delete the hotspot record
	if err := e.App.Delete(hotspotRecord); err != nil {
		e.App.Logger().Error("Failed to delete hotspot", "error", err.Error(), "hotspotId", hotspotId)
		lib.ShowToast(e, lib.Toast{Type: lib.ToastError, Key: "hotspot_delete_error"})
		e.Response.WriteHeader(http.StatusInternalServerError)
		return nil
	}

	// Delete paired hotspot if it exists
	if pairedHotspotId != "" {
		pairedRecord, err := e.App.FindRecordById("hotspots", pairedHotspotId)
		if err == nil {
			// Find rooms referencing the paired hotspot
			var pairedRoomRecords []*core.Record
			e.App.RecordQuery("rooms").
				AndWhere(dbx.Like("hotspots", pairedHotspotId)).
				All(&pairedRoomRecords)

			// Remove paired hotspot from rooms
			for _, room := range pairedRoomRecords {
				hotspotok := room.GetStringSlice("hotspots")
				var updatedHotspotok []string
				for _, id := range hotspotok {
					if id != pairedHotspotId {
						updatedHotspotok = append(updatedHotspotok, id)
					}
				}
				room.Set("hotspots", updatedHotspotok)
				e.App.Save(room)
			}

			// Delete the paired hotspot
			if err := e.App.Delete(pairedRecord); err != nil {
				e.App.Logger().Warn("Failed to delete paired hotspot", "error", err.Error(), "pairedHotspotId", pairedHotspotId)
			}
		}
	}

	lib.ShowToast(e, lib.Toast{Type: lib.ToastSuccess, Key: "hotspot_deleted"})
	return nil
}

